#!/usr/bin/env node
/**
 * Pasumai Tech — Tamil Nadu Agri App
 * ------------------------------------------------------------------
 * SINGLE-FILE full-stack build: frontend (embedded HTML/CSS/JS) +
 * backend (Express API) combined into one runnable file.
 *
 * The original project had:
 *   - a static index.html prototype (frontend)
 *   - a separate Express + Firebase Firestore backend (backend/)
 *
 * This file merges both. To keep it a true single file with zero
 * external setup (no Firebase project/credentials required), the
 * Firestore layer has been swapped for a tiny in-memory data store
 * that mirrors the same collections, fields and seed data. All the
 * original API routes and behaviour are preserved.
 *
 * Run:
 *   npm install express cors
 *   node server.js
 *   -> open http://localhost:4000
 *
 * API is available under /api/* (same routes as the original backend).
 * ------------------------------------------------------------------
 */

'use strict';

const express = require('express');
const cors = require('cors');

// ============================================================
// FRONTEND — original index.html, embedded as base64 so it can
// live inside this single JS file without any escaping issues.
// ============================================================
const FRONTEND_HTML_BASE64 = "";
const FRONTEND_HTML = Buffer.from(FRONTEND_HTML_BASE64, 'base64').toString('utf8');

// ============================================================
// BACKEND — in-memory data store (drop-in replacement for the
// Firebase Firestore layer used in the original backend/ folder)
// ============================================================

class ApiError extends Error {
  constructor(status, message) {
    super(message);
    this.status = status;
  }
}

function asyncHandler(fn) {
  return (req, res, next) => Promise.resolve(fn(req, res, next)).catch(next);
}

// ============================================================
// FIRESTORE — optional. If FIREBASE_SERVICE_ACCOUNT is set, all
// writes are persisted to Firestore in the background, and data
// is loaded ("hydrated") from Firestore on startup. If it's not
// set, the app behaves exactly as before (in-memory only).
// ============================================================
let firestore = null;
try {
  if (process.env.FIREBASE_SERVICE_ACCOUNT) {
    const admin = require('firebase-admin');
    const serviceAccount = JSON.parse(process.env.FIREBASE_SERVICE_ACCOUNT);
    if (!admin.apps.length) {
      admin.initializeApp({ credential: admin.credential.cert(serviceAccount) });
    }
    firestore = admin.firestore();
    console.log('[firestore] connected — data will persist across restarts.');
  } else {
    console.warn('[firestore] FIREBASE_SERVICE_ACCOUNT not set — running with in-memory data only (resets on restart).');
  }
} catch (err) {
  console.error('[firestore] failed to initialize, falling back to in-memory only:', err.message);
  firestore = null;
}

// Generic "collection" — mimics just enough of the Firestore API
// surface the original controllers relied on. Reads/writes are
// synchronous against an in-memory Map (so no route code needs to
// change), while writes are also persisted to Firestore in the
// background when it's configured.
function makeCollection(name) {
  const rows = new Map(); // id -> data
  let seq = 1;

  function persist(id, data) {
    if (!firestore) return;
    firestore.collection(name).doc(id).set(data, { merge: true })
      .catch(err => console.error(`[firestore] failed to save ${name}/${id}:`, err.message));
  }

  return {
    name,
    add(data) {
      const id = String(seq++);
      rows.set(id, { ...data });
      persist(id, rows.get(id));
      return { id, ...rows.get(id) };
    },
    get(id) {
      return rows.has(id) ? { id, ...rows.get(id) } : null;
    },
    update(id, patch) {
      if (!rows.has(id)) return null;
      rows.set(id, { ...rows.get(id), ...patch });
      persist(id, rows.get(id));
      return { id, ...rows.get(id) };
    },
    increment(id, field, by = 1) {
      if (!rows.has(id)) return null;
      const cur = rows.get(id);
      const next = { ...cur, [field]: (cur[field] || 0) + by };
      rows.set(id, next);
      persist(id, next);
      return { id, ...next };
    },
    all() {
      return [...rows.entries()].map(([id, v]) => ({ id, ...v }));
    },
    where(pred) {
      return this.all().filter(pred);
    },
    // Loads existing documents from Firestore into memory. Called
    // once at startup, before the server starts accepting traffic.
    async hydrate() {
      if (!firestore) return;
      const snap = await firestore.collection(name).get();
      snap.forEach(doc => {
        rows.set(doc.id, doc.data());
        const n = parseInt(doc.id, 10);
        if (!isNaN(n) && n >= seq) seq = n + 1;
      });
      if (snap.size > 0) console.log(`[firestore] loaded ${snap.size} ${name} from Firestore`);
    },
  };
}

const db = {
  users: makeCollection('users'),
  produce: makeCollection('produce'),
  bids: makeCollection('bids'),
  rawProduce: makeCollection('rawProduce'),
  jobs: makeCollection('jobs'),
  jobApplications: makeCollection('jobApplications'),
  valueAddCompanies: makeCollection('valueAddCompanies'),
  surplusOffers: makeCollection('surplusOffers'),
  partnershipRequests: makeCollection('partnershipRequests'),
  myProducts: makeCollection('myProducts'),
  mandiPrices: makeCollection('mandiPrices'),
};

