function seed() {
  const userRefs = {};
  for (const u of seedUsers) {
    const created = db.users.add({ ...u, createdAt: new Date().toISOString() });
    userRefs[u.role] = created;
  }

  for (const p of seedMandiPrices) {
    db.mandiPrices.add({ ...p, updatedAt: new Date().toISOString() });
  }

  for (const c of seedValueAddCompanies) {
    db.valueAddCompanies.add(c);
  }

  const farmer = userRefs.farmer;

  db.produce.add({
    farmerId: farmer.id, farmerName: farmer.name, cropName: 'Tomato',
    qty: '500 kg', price: 28, unit: 'kg', location: 'Thanjavur',
    bidsCount: 0, status: 'active', createdAt: new Date().toISOString(),
  });
  db.produce.add({
    farmerId: farmer.id, farmerName: farmer.name, cropName: 'Groundnut',
    qty: '300 kg', price: 62, unit: 'kg', location: 'Thanjavur',
    bidsCount: 0, status: 'active', createdAt: new Date().toISOString(),
  });

  db.jobs.add({
    farmerId: farmer.id, farmerName: farmer.name, task: 'Paddy Harvest',
    workersNeeded: 8, pay: 600, date: 'Dec 18', location: 'Thanjavur',
    status: 'open', applicantsCount: 0, createdAt: new Date().toISOString(),
  });

  console.log('\u2705 In-memory store seeded with starter data.');
}

// ---------------------------- controllers ----------------------------

const VALID_ROLES = ['farmer', 'buyer', 'labour'];

// USERS
function login(req, res) {
  const { name, location, role, businessName } = req.body || {};
  if (!name || !String(name).trim()) throw new ApiError(400, 'name is required');
  if (!location || !String(location).trim()) throw new ApiError(400, 'location is required');
  if (!VALID_ROLES.includes(role)) throw new ApiError(400, `role must be one of ${VALID_ROLES.join(', ')}`);

  const existing = db.users.where(u =>
    u.name === String(name).trim() && u.location === String(location).trim() && u.role === role
  )[0];
  if (existing) return res.json(existing);

  const newUser = db.users.add({
    name: String(name).trim(),
    location: String(location).trim(),
    role,
    businessName: businessName ? String(businessName).trim() : null,
    rating: null,
    verified: false,
    createdAt: new Date().toISOString(),
  });
  res.status(201).json(newUser);
}
function getUser(req, res) {
  const user = db.users.get(req.params.id);
  if (!user) throw new ApiError(404, 'User not found');
  res.json(user);
}
function listUsers(req, res) {
  const { role } = req.query;
  const rows = role ? db.users.where(u => u.role === role) : db.users.all();
  res.json(rows);
}

// PRODUCE / BIDS
function listProduce(req, res) {
  const rows = db.produce.all().sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  res.json(rows);
}
function getProduce(req, res) {
  const p = db.produce.get(req.params.id);
  if (!p) throw new ApiError(404, 'Produce listing not found');
  const bids = db.bids.where(b => b.produceId === req.params.id)
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  res.json({ ...p, bids });
}
function createProduce(req, res) {
  const { farmerId, farmerName, cropName, qty, price, unit, location } = req.body || {};
  if (!farmerId || !cropName || !qty || price == null || !unit || !location) {
    throw new ApiError(400, 'farmerId, cropName, qty, price, unit and location are required');
  }
  const listing = db.produce.add({
    farmerId, farmerName: farmerName || null, cropName, qty,
    price: Number(price), unit, location,
    bidsCount: 0, status: 'active', createdAt: new Date().toISOString(),
  });
  res.status(201).json(listing);
}
function placeBid(req, res) {
  const produceId = req.params.id;
  const { buyerId, buyerName, amount } = req.body || {};
  if (!buyerId || amount == null) throw new ApiError(400, 'buyerId and amount are required');
  const produce = db.produce.get(produceId);
  if (!produce) throw new ApiError(404, 'Produce listing not found');

  const bid = db.bids.add({
    produceId, buyerId, buyerName: buyerName || null, amount: Number(amount),
    status: 'pending', createdAt: new Date().toISOString(),
  });
  db.produce.increment(produceId, 'bidsCount', 1);
  res.status(201).json(bid);
}
function acceptBid(req, res) {
  const { bidId } = req.params;
  const bid = db.bids.get(bidId);
  if (!bid) throw new ApiError(404, 'Bid not found');

  db.bids.update(bidId, { status: 'accepted' });
  db.produce.update(bid.produceId, { status: 'sold' });
  db.bids.where(b => b.produceId === bid.produceId && b.status === 'pending' && b.id !== bidId)
    .forEach(b => db.bids.update(b.id, { status: 'rejected' }));

  res.json({ ...bid, status: 'accepted' });
}
function listFarmerProduce(req, res) {
  const { farmerId } = req.params;
  const listings = db.produce.where(p => p.farmerId === farmerId)
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt))
    .map(p => ({ ...p, bids: db.bids.where(b => b.produceId === p.id) }));
  res.json(listings);
}

// RAW PRODUCE
function listRawProduce(req, res) {
  const rows = db.rawProduce.where(r => r.farmerId === req.params.farmerId)
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  res.json(rows);
}
function addRawProduce(req, res) {
  const { farmerId } = req.params;
  const { crop, qty, harvestDate, grade } = req.body || {};
  if (!crop || !qty) throw new ApiError(400, 'crop and qty are required');
  const entry = db.rawProduce.add({
    farmerId, crop, qty, harvestDate: harvestDate || 'Today',
    grade: grade || 'Ungraded', createdAt: new Date().toISOString(),
  });
  res.status(201).json(entry);
}

// JOBS
function listJobs(req, res) {
  const rows = db.jobs.where(j => j.status === 'open')
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  res.json(rows);
}
function getJob(req, res) {
  const job = db.jobs.get(req.params.id);
  if (!job) throw new ApiError(404, 'Job not found');
  res.json(job);
}
function createJob(req, res) {
  const { farmerId, farmerName, task, workersNeeded, pay, date, location } = req.body || {};
  if (!farmerId || !task || !workersNeeded || pay == null) {
    throw new ApiError(400, 'farmerId, task, workersNeeded and pay are required');
  }
  const job = db.jobs.add({
    farmerId, farmerName: farmerName || null, task,
    workersNeeded: Number(workersNeeded), pay: Number(pay),
    date: date || 'soon', location: location || null,
    status: 'open', applicantsCount: 0, createdAt: new Date().toISOString(),
  });
  res.status(201).json(job);
}
function applyToJob(req, res) {
  const jobId = req.params.id;
  const { workerId, workerName } = req.body || {};
  if (!workerId) throw new ApiError(400, 'workerId is required');
  const job = db.jobs.get(jobId);
  if (!job) throw new ApiError(404, 'Job not found');

  const application = db.jobApplications.add({
    jobId, workerId, workerName: workerName || null,
    status: 'pending', appliedAt: new Date().toISOString(),
  });
  db.jobs.increment(jobId, 'applicantsCount', 1);
  res.status(201).json(application);
}
function listWorkerJobs(req, res) {
  const apps = db.jobApplications.where(a => a.workerId === req.params.workerId)
    .sort((a, b) => new Date(b.appliedAt) - new Date(a.appliedAt))
    .map(a => ({ ...a, job: db.jobs.get(a.jobId) }));
  res.json(apps);
}
function listFarmerJobs(req, res) {
  const rows = db.jobs.where(j => j.farmerId === req.params.farmerId)
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  res.json(rows);
}

// VALUE ADD
function listCompanies(req, res) {
  res.json(db.valueAddCompanies.all());
}
function getCompany(req, res) {
  const c = db.valueAddCompanies.get(req.params.id);
  if (!c) throw new ApiError(404, 'Company not found');
  res.json(c);
}
function createSurplusOffer(req, res) {
  const companyId = req.params.id;
  const { farmerId, crop, qty } = req.body || {};
  if (!farmerId || !crop || !qty) throw new ApiError(400, 'farmerId, crop and qty are required');
  const company = db.valueAddCompanies.get(companyId);
  if (!company) throw new ApiError(404, 'Company not found');

  const offer = db.surplusOffers.add({
    type: 'surplus', farmerId, companyId, companyName: company.name,
    crop, qty, status: 'Pending', date: new Date().toISOString(),
  });
  res.status(201).json(offer);
}
function createPartnershipRequest(req, res) {
  const companyId = req.params.id;
  const { farmerId } = req.body || {};
  if (!farmerId) throw new ApiError(400, 'farmerId is required');
  const company = db.valueAddCompanies.get(companyId);
  if (!company) throw new ApiError(404, 'Company not found');

  const request = db.partnershipRequests.add({
    type: 'partnership', farmerId, companyId, companyName: company.name,
    detail: 'Requested value-add training & equipment partnership',
    status: 'Pending', date: new Date().toISOString(),
  });
  res.status(201).json(request);
}
function listFarmerOffers(req, res) {
  const { farmerId } = req.params;
  const offers = [
    ...db.surplusOffers.where(o => o.farmerId === farmerId),
    ...db.partnershipRequests.where(o => o.farmerId === farmerId),
  ].sort((a, b) => new Date(b.date) - new Date(a.date));
  res.json(offers);
}
function listFarmerProducts(req, res) {
  const rows = db.myProducts.where(p => p.farmerId === req.params.farmerId)
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  res.json(rows);
}
function listAllProducts(req, res) {
  const rows = db.myProducts.all().sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  res.json(rows);
}
function addFarmerProduct(req, res) {
  const { farmerId } = req.params;
  const { name, qty, price, madeWith } = req.body || {};
  if (!name) throw new ApiError(400, 'name is required');
  const product = db.myProducts.add({
    farmerId, name, qty: qty || '?', price: price || '?',
    madeWith: madeWith || null, createdAt: new Date().toISOString(),
  });
  res.status(201).json(product);
}

// PRICES
function listPrices(req, res) {
  const rows = db.mandiPrices.all().sort((a, b) => a.crop.localeCompare(b.crop));
  res.json(rows);
}

// ============================================================
// APP / ROUTES
// ============================================================

const app = express();

const allowedOrigins = (process.env.CORS_ORIGINS || '*').split(',').map(s => s.trim());
app.use(cors({ origin: allowedOrigins.includes('*') ? true : allowedOrigins }));
app.use(express.json());

app.get('/health', (req, res) => res.json({ status: 'ok' }));

// users
const usersRouter = express.Router();
usersRouter.post('/login', asyncHandler(login));
usersRouter.get('/', asyncHandler(listUsers));
usersRouter.get('/:id', asyncHandler(getUser));
app.use('/api/users', usersRouter);

// produce
const produceRouter = express.Router();
produceRouter.get('/', asyncHandler(listProduce));
produceRouter.post('/', asyncHandler(createProduce));
produceRouter.get('/:id', asyncHandler(getProduce));
produceRouter.post('/:id/bids', asyncHandler(placeBid));
app.use('/api/produce', produceRouter);

// bids
const bidsRouter = express.Router();
bidsRouter.patch('/:bidId/accept', asyncHandler(acceptBid));
app.use('/api/bids', bidsRouter);

// jobs
const jobsRouter = express.Router();
jobsRouter.get('/', asyncHandler(listJobs));
jobsRouter.post('/', asyncHandler(createJob));
jobsRouter.get('/:id', asyncHandler(getJob));
jobsRouter.post('/:id/apply', asyncHandler(applyToJob));
app.use('/api/jobs', jobsRouter);

// workers
const workersRouter = express.Router();
workersRouter.get('/:workerId/jobs', asyncHandler(listWorkerJobs));
app.use('/api/workers', workersRouter);

// value-add
const valueAddRouter = express.Router();
valueAddRouter.get('/companies', asyncHandler(listCompanies));
valueAddRouter.get('/companies/:id', asyncHandler(getCompany));
valueAddRouter.post('/companies/:id/surplus-offers', asyncHandler(createSurplusOffer));
valueAddRouter.post('/companies/:id/partnership-requests', asyncHandler(createPartnershipRequest));
valueAddRouter.get('/products', asyncHandler(listAllProducts));
app.use('/api/value-add', valueAddRouter);

// farmers (aggregates several resources under one farmer)
const farmersRouter = express.Router();
farmersRouter.get('/:farmerId/raw-produce', asyncHandler(listRawProduce));
farmersRouter.post('/:farmerId/raw-produce', asyncHandler(addRawProduce));
farmersRouter.get('/:farmerId/produce', asyncHandler(listFarmerProduce));
farmersRouter.get('/:farmerId/jobs', asyncHandler(listFarmerJobs));
farmersRouter.get('/:farmerId/offers', asyncHandler(listFarmerOffers));
farmersRouter.get('/:farmerId/products', asyncHandler(listFarmerProducts));
farmersRouter.post('/:farmerId/products', asyncHandler(addFarmerProduct));
app.use('/api/farmers', farmersRouter);

// prices
const pricesRouter = express.Router();
pricesRouter.get('/', asyncHandler(listPrices));
app.use('/api/prices', pricesRouter);

// ---- frontend ----
app.get('/', (req, res) => {
  res.type('html').send(FRONTEND_HTML);
});

// Any other non-API GET also serves the single-page frontend
app.get(/^(?!\/api|\/health).*/, (req, res) => {
  res.type('html').send(FRONTEND_HTML);
});

app.use('/api', (req, res) => res.status(404).json({ error: 'Not found' }));

app.use((err, req, res, next) => { // eslint-disable-line no-unused-vars
  const status = err.status || 500;
  if (status === 500) console.error(err);
  res.status(status).json({ error: err.message || 'Internal server error' });
});

async function start() {
  // Load any existing data from Firestore (no-op if not configured).
  for (const key of Object.keys(db)) {
    await db[key].hydrate();
  }
  // Only seed demo data the very first time (i.e. Firestore/memory is empty).
  if (db.users.all().length === 0) {
    seed();
    console.log('Seeded demo data.');
  } else {
    console.log('Loaded existing data — skipped seeding.');
  }

  const PORT = process.env.PORT || 4000;
  app.listen(PORT, () => {
    console.log(`Pasumai Tech (frontend + API) listening on http://localhost:${PORT}`);
  });
}

start();
